"use client";

import { CSVUploadCleaner } from "@/components/vendor/CSVUploadCleaner";
import type { LotCSVRow } from "@/lib/lot-ai-cleaner";
import Link from "next/link";
import { useRouter } from "next/navigation";
import { useState } from "react";

export function VendorLotWizard() {
  const router = useRouter();
  const [step, setStep] = useState<1 | 2 | 3 | 4 | 5>(1);
  const [lotSize, setLotSize] = useState(10);
  const [coverImage, setCoverImage] = useState("");
  const [cleaned, setCleaned] = useState<LotCSVRow[]>([]);
  const [aiTitle, setAiTitle] = useState("");
  const [aiDescription, setAiDescription] = useState("");
  const [aiHighlights, setAiHighlights] = useState<string[]>([]);
  const [generatingName, setGeneratingName] = useState(false);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);

  async function generateName(items: LotCSVRow[]) {
    setGeneratingName(true);
    setError(null);
    try {
      const res = await fetch("/api/vendor/lots/generate-name", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ items }),
      });
      const data = await res.json();
      if (!res.ok) {
        setError(typeof data.error === "string" ? data.error : "AI naming failed");
        setGeneratingName(false);
        return;
      }
      setAiTitle(data.name ?? "");
      setAiDescription(data.description ?? "");
      setAiHighlights(Array.isArray(data.highlights) ? data.highlights : []);
      setStep(3);
    } finally {
      setGeneratingName(false);
    }
  }

  async function submit() {
    setError(null);
    setLoading(true);
    try {
      const res = await fetch("/api/vendor/lots", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          title: aiTitle.trim(),
          description: aiDescription.trim() || null,
          highlights: aiHighlights,
          lotSize,
          coverImage: coverImage.trim() || null,
          items: cleaned,
        }),
      });
      const data = await res.json();
      if (!res.ok) {
        setError(data.error ?? "Submit failed");
        return;
      }
      setStep(5);
      router.refresh();
    } finally {
      setLoading(false);
    }
  }

  return (
    <div className="mx-auto max-w-3xl space-y-6">
      <div className="flex flex-wrap gap-2 text-sm font-medium text-slate-600">
        {(["Details", "CSV upload", "AI title", "Review", "Done"] as const).map((label, i) => (
          <span key={label} className={step === i + 1 ? "text-teal-800" : ""}>
            {i + 1}. {label}
            {i < 4 ? " → " : ""}
          </span>
        ))}
      </div>

      {step === 1 ? (
        <div className="space-y-4 rounded-xl border border-teal-100 bg-white p-6">
          <p className="text-sm text-muted">
            Template:{" "}
            <Link href="/templates/lot_upload_template.csv" className="font-medium text-accent hover:underline">
              lot_upload_template.csv
            </Link>
          </p>
          <p className="text-sm text-slate-600">
            Title and description are generated by AI after you upload inventory (step 3).
          </p>
          <label className="block text-sm font-medium text-slate-800">Lot size (units per lot)</label>
          <input
            type="number"
            min={1}
            className="w-40 rounded-lg border border-slate-200 px-3 py-2 text-sm"
            value={lotSize}
            onChange={(e) => setLotSize(Number(e.target.value) || 1)}
          />
          <label className="block text-sm font-medium text-slate-800">Cover image URL (optional)</label>
          <input
            className="w-full rounded-lg border border-slate-200 px-3 py-2 text-sm"
            value={coverImage}
            onChange={(e) => setCoverImage(e.target.value)}
            placeholder="https://..."
          />
          <button
            type="button"
            onClick={() => setStep(2)}
            className="rounded-lg bg-teal-700 px-4 py-2 text-sm font-semibold text-white"
          >
            Continue to upload →
          </button>
        </div>
      ) : null}

      {step === 2 ? (
        <div className="space-y-4 rounded-xl border border-teal-100 bg-white p-6">
          <div>
            <h2 className="text-xl font-bold text-primary">Upload inventory file</h2>
            <p className="mt-1 text-sm text-muted">We clean and standardise with AI before you submit.</p>
          </div>
          <CSVUploadCleaner
            mode="lot"
            apiEndpoint="/api/vendor/lots/clean-csv"
            templateUrl="/templates/lot_upload_template.csv"
            onConfirmed={(data) => {
              const rows = data as LotCSVRow[];
              setCleaned(rows);
              void generateName(rows);
            }}
            onReset={() => setCleaned([])}
          />
          <button
            type="button"
            onClick={() => setStep(1)}
            className="text-sm font-medium text-accent hover:underline"
          >
            ← Back to details
          </button>
        </div>
      ) : null}

      {step === 3 ? (
        <div className="space-y-6 rounded-xl border border-teal-100 bg-white p-6">
          <div>
            <h2 className="flex items-center gap-2 text-xl font-bold text-primary">
              <span aria-hidden>🤖</span> AI-generated listing details
            </h2>
            <p className="mt-1 text-sm text-muted">
              Review and edit before proceeding. These appear on your live listing after verification.
            </p>
          </div>
          {generatingName ? (
            <div className="flex flex-col items-center gap-3 py-12">
              <div className="h-12 w-12 animate-spin rounded-full border-4 border-teal-200 border-t-teal-700" />
              <p className="text-sm text-muted">Analysing {cleaned.length} laptop models…</p>
            </div>
          ) : (
            <>
              <div>
                <label className="mb-1 block text-sm font-semibold text-primary">Listing title</label>
                <input
                  value={aiTitle}
                  onChange={(e) => setAiTitle(e.target.value)}
                  maxLength={80}
                  className="w-full rounded-xl border border-slate-300 px-4 py-3 text-sm font-semibold text-primary focus:border-transparent focus:ring-2 focus:ring-teal-500"
                />
                <div className="mt-1 flex justify-between text-xs text-muted">
                  <span>Keep under 70 characters for best display</span>
                  <span>{aiTitle.length}/80</span>
                </div>
              </div>
              <div>
                <label className="mb-1 block text-sm font-semibold text-primary">Description</label>
                <textarea
                  value={aiDescription}
                  onChange={(e) => setAiDescription(e.target.value)}
                  rows={3}
                  maxLength={200}
                  className="w-full resize-none rounded-xl border border-slate-300 px-4 py-3 text-sm focus:border-transparent focus:ring-2 focus:ring-teal-500"
                />
                <div className="mt-1 flex justify-between text-xs text-muted">
                  <span>Factual, professional tone</span>
                  <span>{aiDescription.length}/200</span>
                </div>
              </div>
              <div>
                <label className="mb-2 block text-sm font-semibold text-primary">Highlights</label>
                <div className="mb-2 flex flex-wrap gap-2">
                  {aiHighlights.map((h, i) => (
                    <div
                      key={`${h}-${i}`}
                      className="flex items-center gap-1 rounded-full bg-teal-50 px-3 py-1.5 text-sm text-teal-900"
                    >
                      <span>{h}</span>
                      <button
                        type="button"
                        onClick={() => setAiHighlights((hs) => hs.filter((_, j) => j !== i))}
                        className="text-xs text-teal-600 hover:text-red-600"
                        aria-label="Remove highlight"
                      >
                        ×
                      </button>
                    </div>
                  ))}
                  {aiHighlights.length < 5 ? (
                    <button
                      type="button"
                      onClick={() => {
                        const val = window.prompt("Add highlight (max 40 chars):");
                        if (val && val.length <= 40) setAiHighlights((h) => [...h, val.trim()]);
                      }}
                      className="rounded-full border border-dashed border-slate-300 px-3 py-1.5 text-xs text-muted hover:border-teal-500 hover:text-teal-800"
                    >
                      + Add
                    </button>
                  ) : null}
                </div>
              </div>
              <button
                type="button"
                onClick={() => void generateName(cleaned)}
                className="text-xs text-muted underline hover:text-teal-700"
              >
                Regenerate with AI
              </button>
              {error ? <p className="text-sm text-red-700">{error}</p> : null}
              <div className="flex gap-3">
                <button
                  type="button"
                  onClick={() => setStep(2)}
                  className="flex-1 rounded-xl border border-slate-300 py-3 font-medium text-slate-700 hover:bg-slate-50"
                >
                  ← Back
                </button>
                <button
                  type="button"
                  disabled={!aiTitle.trim()}
                  onClick={() => setStep(4)}
                  className="flex-[2] rounded-xl bg-teal-700 px-8 py-3 font-semibold text-white disabled:opacity-50"
                >
                  Continue to review →
                </button>
              </div>
            </>
          )}
        </div>
      ) : null}

      {step === 4 ? (
        <div className="space-y-4 rounded-xl border border-teal-100 bg-white p-6">
          <p className="text-sm text-slate-700">
            <strong>{cleaned.length}</strong> line items ·{" "}
            <strong>{cleaned.reduce((s, r) => s + r.count, 0)}</strong> total units ·{" "}
            <strong>{lotSize}</strong> units per lot
          </p>
          <div className="rounded-lg border border-slate-100 bg-slate-50 p-3 text-sm">
            <p className="font-semibold text-primary">{aiTitle}</p>
            <p className="mt-1 text-muted">{aiDescription}</p>
          </div>
          <button type="button" className="text-sm font-medium text-accent hover:underline" onClick={() => setStep(3)}>
            ← Edit AI details
          </button>
          {error ? <p className="text-sm text-red-700">{error}</p> : null}
          <button
            type="button"
            disabled={loading || cleaned.length === 0}
            onClick={() => void submit()}
            className="rounded-lg bg-teal-700 px-4 py-2 text-sm font-semibold text-white disabled:opacity-50"
          >
            {loading ? "Submitting…" : "Submit for verification"}
          </button>
        </div>
      ) : null}

      {step === 5 ? (
        <div className="rounded-xl border border-emerald-200 bg-emerald-50 p-6 text-emerald-950">
          <p className="font-semibold">Lot submitted</p>
          <p className="mt-2 text-sm">Our team will verify before it goes live.</p>
          <Link href="/vendor/lots" className="mt-4 inline-block text-sm font-medium text-teal-800 hover:underline">
            View lots →
          </Link>
        </div>
      ) : null}
    </div>
  );
}
